{"type":"doc","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"compose()"},{"type":"text","text":" — это функция-комбинатор, которая собирает несколько функций в одну:"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"code"}],"text":"compose(f, g, h)(x)"},{"type":"text","text":" эквивалентно "},{"type":"text","marks":[{"type":"code"}],"text":"f(g(h(x)))"},{"type":"text","text":" (выполняет "},{"type":"text","marks":[{"type":"bold"}],"text":"справа налево"},{"type":"text","text":")."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Минимальная реализация (ES6)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// Уни-версия: последний обработчик может принять много аргументов
const compose = (...fns) => (...args) =>
  fns.reduceRight(
    (acc, fn) => [fn(...acc)],
    args
  )[0];

// Пример
const trim = s => s.trim();
const toInt = s => parseInt(s, 10);
const inc  = n => n + 1;

const parseAndInc = compose(inc, toInt, trim);
parseAndInc(' 41 '); // 42
