getUserNameLoud(7).then(console.log); // 'TIM'
"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Типобезопасная версия для TypeScript (практичные перегрузки)"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"(Покрывают до 4 функций; можно расширить по аналогии.)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"type Unary<A, R> = (a: A) => R;

