console.log(slowSquare(5)); // Вычисляю... → 25 (заново)
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"📉 Каждый раз функция делает одинаковую работу."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"🔹 С мемоизацией"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function memoize(fn) {
  const cache = {};
  return function (arg) {
    if (cache[arg] !== undefined) {
      console.log('Из кэша');
      return cache[arg];
    }
    console.log('Вычисляю...');
    const result = fn(arg);
    cache[arg] = result;
    return result;
  };
}

const fastSquare = memoize(n => n * n);

console.log(fastSquare(5)); // Вычисляю... → 25
console.log(fastSquare(5)); // Из кэша → 25
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"📘 Теперь повторный вызов "},{"type":"text","marks":[{"type":"bold"}],"text":"мгновенный"},{"type":"text","text":", потому что результат берётся из памяти."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"🔹 Пример с несколькими аргументами"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"function memoize(fn) {
  const cache = new Map();
  return function (...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) return cache.get(key);
    const result = fn(...args);
    cache.set(key, result);
    return result;
  };
}

const add = (a, b) => a + b;
const memoAdd = memoize(add);

console.log(memoAdd(2, 3)); // 5 (новый расчёт)
console.log(memoAdd(2, 3)); // 5 (из кэша)
